-- =====================================================================
-- emission_factors seed - generated from "Main DB.csv" (BAFU 2025)
-- domain stamped by section row-range; is_legacy derived. Run ONCE in pgAdmin.
-- This DROPS and rebuilds the table, then loads all rows.
-- =====================================================================
DROP TABLE IF EXISTS emission_factors CASCADE;

CREATE TABLE emission_factors (
    ef_id          BIGSERIAL PRIMARY KEY,
    domain         TEXT NOT NULL,
    category       TEXT NOT NULL,
    sub_category   TEXT,
    group_name     TEXT,
    specific_type  TEXT NOT NULL,
    dataset_name   TEXT NOT NULL,
    geography      TEXT NOT NULL,
    unit           TEXT NOT NULL,
    gwp_100        NUMERIC(20, 6) NOT NULL,
    is_legacy      BOOLEAN NOT NULL DEFAULT false,
    search_text    TEXT,
    source_db      TEXT DEFAULT 'BAFU 2025',
    created_at     TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    updated_at     TIMESTAMPTZ DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT uq_emission_factors_dedup UNIQUE (domain, dataset_name, geography, unit)
);

CREATE INDEX idx_emission_factors_domain_unit ON emission_factors (domain, unit);
CREATE INDEX idx_emission_factors_taxonomy    ON emission_factors (domain, category, sub_category, group_name);
CREATE INDEX idx_emission_factors_geography   ON emission_factors (geography);
CREATE INDEX idx_emission_factors_active      ON emission_factors (domain, unit) WHERE is_legacy = false;
CREATE EXTENSION IF NOT EXISTS pg_trgm;
CREATE INDEX idx_emission_factors_search_trgm ON emission_factors USING gin (search_text gin_trgm_ops);

ON CONFLICT ON CONSTRAINT uq_emission_factors_dedup DO NOTHING;

